  deltaBox.appendChild(make('span','percent',percent===null?'Percentage unavailable':(percent>0?'+':'')+percent.toFixed(1)+'%')); values.appendChild(deltaBox); inner.appendChild(values);
  const max=Math.max(Math.abs(before),Math.abs(after),1); const bars=make('div','bars');
