  addBar(data.fromLabel?String(data.fromLabel):'Before',before,'before'); addBar(data.toLabel?String(data.toLabel):'After',after,'after'); inner.appendChild(bars);
  if(data.note) inner.appendChild(make('p','note',String(data.note))); frame.appendChild(inner);
}
